  // Instrução original encontrada via "what writes": SUB ECX, EAX (2B C8)
  // Seguida por: MOV [EBX+4C], ECX (89 4B 4C)
  // Total: 5 bytes — perfeito para um JMP (que usa exatamente 5 bytes)

  [ENABLE]
